// ===== Extraer storyboard =====
let rawStoryboard = $input.first().json.output || ""; // viene del nodo Storyboard_escenas

// Quitar los ```json y espacios
rawStoryboard = rawStoryboard.replace(/```json/g, "").replace(/```/g, "").trim();

// Parsear JSON
let parsedStoryboard = {};
try {
  parsedStoryboard = JSON.parse(rawStoryboard);
} catch (e) {
  console.error("Error parseando storyboard:", e);
  parsedStoryboard = { storyboard: [] };
}

// ===== Extraer voz en off (si existe) =====
let rawVoz = $input.first().json.voz_en_off || ""; // si viene del nodo AI Agent2
rawVoz = rawVoz.replace(/```json/g, "").replace(/```/g, "").trim();
let parsedVoz = {};
try {
  parsedVoz = JSON.parse(rawVoz);
} catch (e) {
  console.error("Error parseando voz:", e);
  parsedVoz = { voz_en_off: [] };
}

// ===== Construir escenas finales =====
const escenas_final = (parsedStoryboard.storyboard || []).map(e => {
  const vozEscena = (parsedVoz.voz_en_off || []).find(v => v.escena === e.escena);
  return {
    id: e.escena,
    dibujo: e.dibujo_sugerido,
    texto: e.texto_en_pantalla,
    animacion: e.animacion,
    duracion: e.duracion_segundos,
    voz: vozEscena ? vozEscena.texto : ""
  };
});

// ===== Retornar JSON final =====
return {
  json: {
    video_type: "whiteboard",
    idioma: $json["idioma"] || "ES",
    estilo: $json["Estilo Visual"] || "Educativo",
    CTA_final: $json["CTA"] || "",
    escenas: escenas_final
  }
};

